"use client";

import { useState } from "react";

import { getGithubLoginUrl } from "@/lib/api";

type AuthCardProps = {
  mode: "login" | "register";
};

export function AuthCard({ mode }: AuthCardProps) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [step, setStep] = useState<"credentials" | "oauth">("credentials");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const canContinue = email.length > 3 && password.length > 3;

  const handleGithubAuth = async () => {
    try {
      setLoading(true);
      setError("");
      const url = await getGithubLoginUrl();
      window.location.href = url;
    } catch {
      setError("Не удалось инициировать GitHub OAuth.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-flow">
      <div className="auth-card dark">
        <h1>FLOW</h1>
        <p className="terminal-subtitle">
          {mode === "login" ? "SECURE_ACCESS_REQUIRED" : "REQUEST_ACCESS_TOKEN"}
        </p>
        <label className="auth-label">EMAIL ADDRESS</label>
        <input
          className="field dark"
          placeholder="developer@ethereal.sys"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
        />
        <label className="auth-label">PASSWORD</label>
        <input
          className="field dark"
          placeholder="•••••••••"
          type="password"
          value={password}
          onChange={(event) => setPassword(event.target.value)}
        />
        <button
          className="btn primary"
          onClick={() => setStep("oauth")}
          disabled={!canContinue}
        >
          {mode === "login" ? "Initialize Session →" : "Request Access →"}
        </button>
      </div>

      {step === "oauth" && canContinue && (
        <div className="oauth-panel">
          <div className="oauth-separator" />
          <p className="muted small">Continue with GitHub identity</p>
          <button className="github-orb" onClick={handleGithubAuth} disabled={loading}>
            <svg width="32" height="32" viewBox="0 0 16 16" fill="currentColor" aria-hidden="true">
              <path d="M8 0C3.58 0 0 3.58 0 8a8 8 0 0 0 5.47 7.59c.4.07.55-.17.55-.38v-1.32c-2.22.48-2.69-1.07-2.69-1.07-.36-.92-.89-1.16-.89-1.16-.73-.5.05-.49.05-.49.8.06 1.22.82 1.22.82.72 1.2 1.87.86 2.33.66.07-.52.28-.86.5-1.06-1.77-.2-3.63-.88-3.63-3.95 0-.88.31-1.6.82-2.16-.08-.2-.36-1 .08-2.08 0 0 .67-.22 2.2.82a7.48 7.48 0 0 1 4 0c1.52-1.04 2.2-.82 2.2-.82.44 1.08.16 1.88.08 2.08.5.56.82 1.28.82 2.16 0 3.08-1.86 3.74-3.64 3.94.28.24.54.72.54 1.46v2.16c0 .21.14.46.55.38A8 8 0 0 0 16 8c0-4.42-3.58-8-8-8Z" />
            </svg>
          </button>
        </div>
      )}

      {error && <p className="error">{error}</p>}
    </div>
  );
}
